#include<stdio.h>
#define min(a,b) (a<b?a:b)
#define min3(a,b,c) (min(a,min(b,c)))

main()
{
	int a,b,c;
	scanf("%d%d%d",&a,&b,&c);
	int m=min3(a,b,c);
	if(m>=4)      puts("NO");
	else if(m==1) puts("YES");
	else if(m==3) puts(a==3&&b==3&&c==3?"YES":"NO");
	else          puts((a==2&&b==2||a==2&&c==2||b==2&&c==2)||(a==4&&b==4||a==4&&c==4||b==4&&c==4)?"YES":"NO");
}

